317	func (m *Manager) branchExists(branch string) bool {
318		cmd := exec.Command(
319			m.bin(),
320			"-C", m.RepoDir,
321			"rev-parse", "--verify", "--quiet",
322			"refs/heads/"+branch,
323		)
324		return cmd.Run() == nil
325	}
