331	// gitAt runs git with its working directory set to dir (git -C dir). The
332	// repository commands use RepoDir; the diff commands run inside the worktree,
333	// which is a different directory, so the two cannot share a fixed -C.
334	func (m *Manager) gitAt(dir string, args ...string) ([]byte, error) {
335		full := append([]string{"-C", dir}, args...)
336		cmd := exec.Command(m.bin(), full...)
337	
338		var stdout, stderr bytes.Buffer
339		cmd.Stdout = &stdout
340		cmd.Stderr = &stderr
341	
342		if err := cmd.Run(); err != nil {
343			msg := strings.TrimSpace(stderr.String())
344			if msg == "" {
345				return nil, fmt.Errorf("git %s: %w", strings.Join(args, " "), err)
346			}
347			return nil, fmt.Errorf(
348				"git %s: %w: %s",
349				strings.Join(args, " "),
350				err,
351				msg,
352			)
353		}
354		return stdout.Bytes(), nil
355	}
356	
357	func (m *Manager) bin() string {
358		if m.Git == "" {
359			return "git"
360		}
361		return m.Git
362	}
363	
364	func parseList(out []byte) []Worktree {
365		var (
366			result []Worktree
367			cur    Worktree
368			open   bool
369		)
370		flush := func() {
371			if open {
372				result = append(result, cur)
373				cur = Worktree{}
374				open = false
375			}
376		}
377	
378		for line := range strings.SplitSeq(string(out), "\n") {
379			line = strings.TrimRight(line, "\r")
380			if line == "" {
381				flush()
382				continue
383			}
384			open = true
385	
386			key, value, _ := strings.Cut(line, " ")
387			switch key {
388			case "worktree":
389				cur.Path = value
390			case "HEAD":
391				cur.Head = value
392			case "branch":
393				cur.Branch = strings.TrimPrefix(value, "refs/heads/")
394			case "bare":
395				cur.Bare = true
396			case "detached":
397				cur.Detached = true
398			}
399		}
400		flush()
401		return result
402	}
